#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_NAME 50

typedef struct {
    char name[MAX_NAME];
    int age;
    double score;
} Record;

int main(void) {
    const char *filepath = "records.txt";

    // 1. Write structured data to a text file safely
    FILE *fp_out = fopen(filepath, "w");
    if (fp_out == NULL) {
        perror("Error opening file for writing");
        return EXIT_FAILURE;
    }

    Record r1 = {"Alice Smith", 23, 94.5};
    Record r2 = {"Bob Jones", 29, 88.2};

    // Using fprintf to format structural representation into text stream
    fprintf(fp_out, "%s|%d|%.2f\n", r1.name, r1.age, r1.score);
    fprintf(fp_out, "%s|%d|%.2f\n", r2.name, r2.age, r2.score);

    fclose(fp_out);
    printf("Records exported to %s successfully.\n\n", filepath);

    // 2. Read back structured format via string parsing
    FILE *fp_in = fopen(filepath, "r");
    if (fp_in == NULL) {
        perror("Error opening file for reading");
        return EXIT_FAILURE;
    }

    char buffer[256];
    printf("Reading records:\n");
    printf("-----------------------------\n");

    // Read line-by-line using fgets to prevent buffer exploits, then scan memory with sscanf
    while (fgets(buffer, sizeof(buffer), fp_in) != NULL) {
        Record temp;
        // Parse token-delimited fields securely via format parameters
        int scanned = sscanf(buffer, "%[^|]|%d|%lf", temp.name, &temp.age, &temp.score);
        if (scanned == 3) {
            printf("Name: %s\nAge: %d\nScore: %.2f\n\n", temp.name, temp.age, temp.score);
        } else {
            fprintf(stderr, "Warning: Found corrupt line segment on file parsing\n");
        }
    }

    fclose(fp_in);
    return EXIT_SUCCESS;
}

