#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int id;
    char grade;
    float balance;
} Account;

int main(void) {
    const char *filepath = "accounts.bin";

    // 1. Write an array of structures directly to binary
    FILE *fp = fopen(filepath, "wb+"); // Open for read and write in binary mode
    if (!fp) {
        perror("Binary initialization error");
        return EXIT_FAILURE;
    }

    Account clients[3] = {
        {101, 'A', 2500.50f},
        {102, 'B', 120.75f},
        {103, 'C', 9990.00f}
    };

    size_t written = fwrite(clients, sizeof(Account), 3, fp);
    printf("Successfully wrote %zu records to %s.\n", written, filepath);

    // 2. Read the 2nd record directly using random access seeking
    long offset = 1 * sizeof(Account); // Locate index 1 (0-based indexing)

    if (fseek(fp, offset, SEEK_SET) != 0) {
        perror("Seeking location failure");
        fclose(fp);
        return EXIT_FAILURE;
    }

    // Confirm stream position indicator using ftell
    long current_pos = ftell(fp);
    printf("Stream cursor successfully verified at byte %ld.\n", current_pos);

    Account single_client;
    size_t read_count = fread(&single_client, sizeof(Account), 1, fp);
    if (read_count == 1) {
        printf("\n--- Loaded Record [Index 1] ---\n");
        printf("ID: %d\nGrade: %c\nBalance: $%.2f\n\n", 
               single_client.id, single_client.grade, single_client.balance);
    }

    // 3. Mutate balance state on index 1 dynamically and write modifications back
    single_client.balance += 5000.00f; // Increase balance

    // Reposition back to same record start point
    fseek(fp, offset, SEEK_SET);
    fwrite(&single_client, sizeof(Account), 1, fp);

    // Rewind back to read the entire set showing alterations
    rewind(fp);
    printf("--- Full Database Snapshot Post-Mutation ---\n");
    Account reader;
    while (fread(&reader, sizeof(Account), 1, fp) == 1) {
        printf("ID: %d, Grade: %c, Balance: $%.2f\n", 
               reader.id, reader.grade, reader.balance);
    }

    fclose(fp);
    return EXIT_SUCCESS;
}

