    FILE *fp = fopen("log.txt", "a");
    if (!fp) return;
    time_t raw = time(NULL);
    char *time_str = ctime(&raw);
    time_str[24] = '\0'; // Remove newline
    fprintf(fp, "[%s] %s\n", time_str, msg);
