To do this, use fseek with SEEK_END to point from the end of the file:

```c
#include <stdio.h>
#include <stdlib.h>

void print_last_10(const char *filename) {
    FILE *fp = fopen(filename, "rb");
    if (!fp) return;
    if (fseek(fp, -10, SEEK_END) == 0) {
        unsigned char bytes[10];
        size_t read = fread(bytes, 1, 10, fp);
        for(size_t i = 0; i < read; ++i) {
            printf("%02X ", bytes[i]);
        }
        printf("\n");
    } else {
        perror("File seek failed");
    }
    fclose(fp);
}
```

