#include <stdio.h>

typedef struct { int id; float price; } Item;

int update_item_price(int index, float new_price) {
    FILE *fp = fopen("items.bin", "r+b");
    if (!fp) return -1;

    if (fseek(fp, index * sizeof(Item), SEEK_SET) != 0) {
        fclose(fp);
        return -1;
    }

    Item current;
    if (fread(&current, sizeof(Item), 1, fp) != 1) {
        fclose(fp);
        return -1;
    }

    current.price = new_price;

    if (fseek(fp, index * sizeof(Item), SEEK_SET) != 0) {
        fclose(fp);
        return -1;
    }

    if (fwrite(&current, sizeof(Item), 1, fp) != 1) {
        fclose(fp);
        return -1;
    }

    fclose(fp);
    return 0;
}
```

